import React from 'react';
import PageLoader from '../../components/common/PageLoader';

const Loading = () => {

    const customLoading = [
        [
            { type: 'avatar' },
            { type: 'group', children: [{ width: 5 }, { width: 6 }] },
            { type: 'line', width: 1 }
        ],
        [{ type: 'line', width: 8 }],
        [{ type: 'line', width: 9 }],
    ];

    return (
        <div className='admin-pager'>
            <header className='admin-pager-head'>
                <div className='admin-pager-title'>
                    <span><h2>Loading Indicators</h2><p>Loading Design and Style</p></span>
                </div>
            </header>
            <div className='admin-pager-body'>
                <div className='pagelet'><div className='pagelet-in'>
                    <div className='flex-row'>
                        <h4>Loading Icons</h4>
                        <ul className='flex-case wrap template-loading'>
                            <li> <span><div className='loader-spinner'></div></span><p>classic-spinner</p> </li>
                            <li> <span><div className='loader-ball-pulse'><div></div><div></div><div></div></div></span><p>ball-pulse</p> </li>
                            <li> <span><div className='loader-ball-grid-pulse'>{[...Array(9)].map((_, i) => <div key={i}></div>)} </div></span><p>ball-grid-pulse</p></li>
                            <li> <span><div className='loader-ball-grid-beat'>{[...Array(9)].map((_, i) => <div key={i}></div>)}</div> </span> <p>ball-grid-beat</p> </li>
                            <li> <span><div className='loader-ball-clip-rotate-pulse'><div></div><div></div></div></span><p>ball-clip-rotate-pulse</p></li>
                            <li> <span><div className='loader-square-spin'><div></div></div></span><p>square-spin</p></li>
                            <li> <span><div className='loader-ball-clip-rotate-multiple'><div></div><div></div></div></span><p>ball-clip-rotate-multiple</p></li>
                            <li> <span><div className='loader-ball-pulse-rise'> {[...Array(5)].map((_, i) => <div key={i}></div>)} </div></span><p>ball-pulse-rise</p></li>
                            <li> <span><div className='loader-ball-rotate-multiple'><div></div><div></div></div></span><p>ball-rotate-multiple</p></li>
                            <li> <span><div className='loader-cube-transition'><div></div><div></div></div></span><p>cube-transition</p></li>
                            <li> <span><div className='loader-ball-scale-multiple'><div></div><div></div><div></div></div></span><p>ball-scale-multiple</p></li>
                            <li> <span><div className='loader-ball-scale-ripple-multiple'><div></div><div></div><div></div></div></span><p>ball-scale-ripple-multiple</p></li>
                            <li> <span><div className='loader-line-scale'><div></div><div></div><div></div><div></div><div></div></div></span><p>line-scale</p> </li>
                            <li> <span><div className='loader-line-scale-party'> <div></div><div></div><div></div><div></div> </div> </span> <p>line-scale-party</p> </li>
                            <li> <span><div className='loader-line-scale-pulse-out'> <div></div><div></div><div></div><div></div><div></div> </div> </span> <p>line-scale-pulse-out</p> </li>
                            <li> <span><div className='loader-line-scale-pulse-out-rapid'> <div></div><div></div><div></div><div></div><div></div> </div> </span> <p>line-scale-pulse-out-rapid</p> </li>
                        </ul>
                    </div>
                </div></div>

                <h4>Page, Pagelet Loading</h4>
                <div className='flex-column wrap'>
                    <div className='w5'> <PageLoader type='profile' asPagelet /> </div>
                    <div className='w5'> <PageLoader type='profileSquare' asPagelet /> </div>
                    <div className='w5'><PageLoader blueprint={customLoading} asPagelet /></div>
                </div>
                <div className='flex-column wrap'>
                    <div className='w5'> <PageLoader type='column' count={3} asPagelet /> </div>
                    <div className='w5 template-is-loading-a'> <PageLoader type='cards' asPagelet /> </div>
                    <div className='w5 template-is-loading-b'> <PageLoader blueprint={[[{ type: 'line', width: 5 }, { type: 'line', width: 5 }]]} /> </div>
                </div>
            </div>

        </div>);
};
export default Loading;